import{_ as s,o as i,c as e,ae as n}from"./chunks/framework.D0EcU_Ug.js";const t="/linux-docs/assets/fastfetch-arch.SSSiiHpw.png",l="/linux-docs/assets/fastfetch-cachyos.DASe2YFZ.png",g=JSON.parse('{"title":"Linux 生存手册","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux-survival-guide.md","filePath":"notes/linux-survival-guide.md"}'),d={name:"notes/linux-survival-guide.md"};function h(o,a,p,r,c,k){return i(),e("div",null,[...a[0]||(a[0]=[n('<h1 id="linux-生存手册" tabindex="-1">Linux 生存手册 <a class="header-anchor" href="#linux-生存手册" aria-label="Permalink to &quot;Linux 生存手册&quot;">​</a></h1><blockquote><p>这篇是偏“通用经验”的长期手册，主要收纳跨发行版也能复用的配置、排障和环境搭建笔记。随着我从 Arch / CachyOS 迁到 NixOS，里面有些做法会继续保留，有些则会逐步拆分成独立文章。</p></blockquote><p>Arch 时期：</p><p><img src="'+t+'" alt="Arch fastfetch"></p><p>CachyOS 时期：</p><p><img src="'+l+`" alt="CachyOS fastfetch"></p><h2 id="🌐-吉林大学校园网认证-drcom" tabindex="-1">🌐 吉林大学校园网认证（Drcom） <a class="header-anchor" href="#🌐-吉林大学校园网认证-drcom" aria-label="Permalink to &quot;🌐 吉林大学校园网认证（Drcom）&quot;">​</a></h2><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/AndrewLawrence80/jlu-drcom-client</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jlu-drcom-client</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 修改 config.h 中的账号密码等参数</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./drclient_jlu</span></span></code></pre></div><p>或者可以用我的c++跨平台版本，地址：<a href="https://github.com/yuzujr/drcom-client-cpp" target="_blank" rel="noreferrer">github</a></p><p><strong>有线连接</strong></p><p>需要使用<code>nmcli</code>或者桌面环境自带的图形化配置界面，配置<code>有线连接</code>：</p><ul><li><code>克隆 MAC 地址</code>：校园网账号的物理地址</li><li><code>IPv4</code>：方式改为<code>手动</code>，配置<code>DNS服务器</code>、<code>IP地址</code>、<code>子网掩码</code>、<code>网关</code>。</li></ul><p>重启有线连接后，重新运行<code>drclient_jlu</code>。</p><h2 id="🇨🇳-科学上网" tabindex="-1">🇨🇳 科学上网 <a class="header-anchor" href="#🇨🇳-科学上网" aria-label="Permalink to &quot;🇨🇳 科学上网&quot;">​</a></h2><p>只需要下载<a href="https://github.com/clash-verge-rev/clash-verge-rev" target="_blank" rel="noreferrer">clash verge rev</a>，</p><p>然后通过url导入配置文件即可。</p><p>进阶用户可选择直接运行mihomo内核，自行控制proxy providers和rule providers。</p><p>ui可使用**<a href="https://github.com/MetaCubeX/metacubexd" target="_blank" rel="noreferrer">metacubexd</a>**。</p><h2 id="🪛-n卡驱动" tabindex="-1">🪛 n卡驱动 <a class="header-anchor" href="#🪛-n卡驱动" aria-label="Permalink to &quot;🪛 n卡驱动&quot;">​</a></h2><p>提前安装<code>nvidia</code>(如果使用50系显卡，此处应为<code>nvidia-open</code>)、<code>nvidia-settings</code>、<code>nvidia-utils</code>。</p><h3 id="步骤-1-启用-nvidia-drm" tabindex="-1">步骤 1：启用 nvidia_drm <a class="header-anchor" href="#步骤-1-启用-nvidia-drm" aria-label="Permalink to &quot;步骤 1：启用 nvidia_drm&quot;">​</a></h3><p>修改<code>/etc/default/grub</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GRUB_CMDLINE_LINUX_DEFAULT=&quot;nvidia_drm.modeset=1&quot;</span></span></code></pre></div><p>在原有的参数中加入<code>nvidia_drm.modeset=1</code>即可。</p><h3 id="步骤2-桌面环境设置n卡优先" tabindex="-1">步骤2：桌面环境设置n卡优先 <a class="header-anchor" href="#步骤2-桌面环境设置n卡优先" aria-label="Permalink to &quot;步骤2：桌面环境设置n卡优先&quot;">​</a></h3><p><strong>确认独显位置</strong>：</p><ol><li><code>lspci | grep -E &quot;VGA&quot;</code> 得到独显的pci名，例如<code>01:00.0</code>。</li><li><code>ll /dev/dri/by-path/</code>得到pci名对应的<code>cardx</code>和<code>renderDxxx</code></li></ol><p>在下面的设置中，将独显放在前面</p><ul><li><p>KDE：创建<code>~/.config/plasma-workspace/env/kwin-drm.sh</code></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/bash</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KWIN_DRM_DEVICES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/dev/dri/card0:/dev/dri/card1&quot;</span></span></code></pre></div></li><li><p>Hyprland：在hyprland或者uwsm配置文件中加入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AQ_DRM_DEVICES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/dev/dri/card0:/dev/dri/card1&quot;</span></span></code></pre></div></li><li><p>Niri：在任意niri配置文件（例如<code>~/.config/niri/config.kdl</code>）中加入</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>debug {</span></span>
<span class="line"><span>    render-drm-device &quot;/dev/dri/renderD128&quot; // 独显</span></span>
<span class="line"><span>    ignore-drm-device &quot;/dev/dri/renderD129&quot; // （可选）此选项会禁用对应的显卡，将导致笔记本屏幕或外接屏幕无法亮起</span></span>
<span class="line"><span>}</span></span></code></pre></div></li></ul><h3 id="步骤3-验证" tabindex="-1">步骤3：验证 <a class="header-anchor" href="#步骤3-验证" aria-label="Permalink to &quot;步骤3：验证&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsmod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nvidia</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 应输出nvidia_drm等</span></span></code></pre></div><h3 id="步骤4-功率控制" tabindex="-1">步骤4: 功率控制 <a class="header-anchor" href="#步骤4-功率控制" aria-label="Permalink to &quot;步骤4: 功率控制&quot;">​</a></h3><p>查看<code>nvidia-smi</code>的输出，如果显卡的最大功率不是预期值，则需要</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nvidia-powerd.service</span></span></code></pre></div><p>再次查看<code>nvidia-smi</code>，问题解决，并且笔记本的切换功率功能可以使用了</p><h3 id="可选-安装cachyos" tabindex="-1">（可选）安装CachyOS <a class="header-anchor" href="#可选-安装cachyos" aria-label="Permalink to &quot;（可选）安装CachyOS&quot;">​</a></h3><p>使用CachyOS会自动配置显卡驱动，但是安装过程可能会因网络原因失败。</p><h2 id="🖕-关于nvidia的bug" tabindex="-1">🖕 关于Nvidia的BUG <a class="header-anchor" href="#🖕-关于nvidia的bug" aria-label="Permalink to &quot;🖕 关于Nvidia的BUG&quot;">​</a></h2><h3 id="qq-wayland原生启动画面撕裂" tabindex="-1">QQ wayland原生启动画面撕裂 <a class="header-anchor" href="#qq-wayland原生启动画面撕裂" aria-label="Permalink to &quot;QQ wayland原生启动画面撕裂&quot;">​</a></h3><p>尽管已经设置了n卡优先（见<a href="#步骤2桌面环境设置n卡优先">桌面环境设置n卡优先</a>），QQ仍然会使用核显，由于桌面环境本身使用独显渲染，所以会产生大量数据拷贝，并且核显性能低下，如果占满会导致QQ出现马赛克画面撕裂</p><p>问题根源：<code>libglvnd</code>在选择<code>EGL</code>提供者时，选择了<code>mesa</code>，导致使用核显渲染，对于n卡用户来说，应该使用<code>nvidia</code>。</p><p>解决方法：手动指定QQ启动时的<code>EGL</code>提供者</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> __EGL_VENDOR_LIBRARY_FILENAMES=/usr/share/glvnd/egl_vendor.d/10_nvidia.json</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linuxqq</span></span></code></pre></div><h2 id="🔐-登录界面-移除多余桌面环境" tabindex="-1">🔐 登录界面：移除多余桌面环境 <a class="header-anchor" href="#🔐-登录界面-移除多余桌面环境" aria-label="Permalink to &quot;🔐 登录界面：移除多余桌面环境&quot;">​</a></h2><p>删除或重命名以下目录下不需要的 <code>.desktop</code> 文件：</p><ul><li><code>/usr/share/xsessions/</code></li><li><code>/usr/share/wayland-sessions/</code></li></ul><h2 id="🧩-kde-设置-windows-风格-alt-tab" tabindex="-1">🧩 KDE 设置 Windows 风格 Alt+Tab <a class="header-anchor" href="#🧩-kde-设置-windows-风格-alt-tab" aria-label="Permalink to &quot;🧩 KDE 设置 Windows 风格 Alt+Tab&quot;">​</a></h2><h3 id="步骤一-移除延迟" tabindex="-1">步骤一：移除延迟 <a class="header-anchor" href="#步骤一-移除延迟" aria-label="Permalink to &quot;步骤一：移除延迟&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kwriteconfig5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/kwinrc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --group</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TabBox</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --key</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DelayTime</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qdbus</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org.kde.KWin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /KWin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reconfigure</span></span></code></pre></div><h3 id="步骤二-设置任务切换器样式" tabindex="-1">步骤二：设置任务切换器样式 <a class="header-anchor" href="#步骤二-设置任务切换器样式" aria-label="Permalink to &quot;步骤二：设置任务切换器样式&quot;">​</a></h3><ul><li>打开「设置」 → 「窗口管理」 → 「任务切换器」</li><li>取消勾选「显示选中窗口」</li><li>获取新样式：下载 &quot;Aqua Medium Icons&quot;</li></ul><h2 id="🎯-更改鼠标指针样式与大小" tabindex="-1">🎯 更改鼠标指针样式与大小 <a class="header-anchor" href="#🎯-更改鼠标指针样式与大小" aria-label="Permalink to &quot;🎯 更改鼠标指针样式与大小&quot;">​</a></h2><h3 id="更换鼠标主题-适用于-x11" tabindex="-1">更换鼠标主题（适用于 X11） <a class="header-anchor" href="#更换鼠标主题-适用于-x11" aria-label="Permalink to &quot;更换鼠标主题（适用于 X11）&quot;">​</a></h3><p>修改 <code>/usr/share/icons/default/index.theme</code></p><h3 id="修改-xresources" tabindex="-1">修改 <code>.Xresources</code> <a class="header-anchor" href="#修改-xresources" aria-label="Permalink to &quot;修改 \`.Xresources\`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Xcursor.theme:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Xcursor.size:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 24</span></span></code></pre></div><h3 id="修改-gnome-鼠标大小" tabindex="-1">修改 GNOME 鼠标大小 <a class="header-anchor" href="#修改-gnome-鼠标大小" aria-label="Permalink to &quot;修改 GNOME 鼠标大小&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gsettings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org.gnome.desktop.interface</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cursor-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 24</span></span></code></pre></div><h2 id="🖕-windows作为ssh服务器如何配置免密登录" tabindex="-1">🖕 windows作为ssh服务器如何配置免密登录 <a class="header-anchor" href="#🖕-windows作为ssh服务器如何配置免密登录" aria-label="Permalink to &quot;🖕 windows作为ssh服务器如何配置免密登录&quot;">​</a></h2><p>前期所有工作都和Linux配置一样</p><p>然而会发现这样仍然无法免密登录</p><p><strong>解决方法</strong>：</p><p>打开<code>C\\ProgramData\\ssh\\sshd_config</code></p><p>注释下面两行</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Match Group administrators</span></span>
<span class="line"><span>       AuthorizedKeysFile __PROGRAMDATA__/ssh/administrators_authorized_keys</span></span></code></pre></div><p>然后在<code>服务</code>里面重启<code>OpenSSH SSH Server</code>服务就完成了。</p><h2 id="🎮-steam-如何识别本地游戏文件" tabindex="-1">🎮 steam 如何识别本地游戏文件 <a class="header-anchor" href="#🎮-steam-如何识别本地游戏文件" aria-label="Permalink to &quot;🎮 steam 如何识别本地游戏文件&quot;">​</a></h2><p>使用Windows + Linux双系统，就可以轻松在两个系统之间迁移游戏文件，不需要重复下载。 但是steam想要识别到游戏文件，需要遵循以下步骤：</p><ol><li>点安装（让steam在库中创建文件夹，使其能够识别）</li><li>复制已下好的文件，到这个文件夹中 (一般是<code>Steam/steamapps/common/游戏名</code>，<code>Steam</code>目录在Linux下一般是<code>~/.local/share/Steam</code>)</li><li>回steam点卸载（不要害怕！这个时候卸的是downloading里的）</li><li>再次点安装，此时steam就能检测到复制过去的文件了</li></ol>`,69)])])}const b=s(d,[["render",h]]);export{g as __pageData,b as default};
